--
-- Table structure for table `caipiao_user_device`
--

DROP TABLE IF EXISTS `caipiao_user_device`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `caipiao_user_device` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `device_id` varchar(64) NOT NULL COMMENT 'thiết bịmã',
  `client_version` varchar(32) DEFAULT '' COMMENT 'phiên bản',
  `browser_type` varchar(64) DEFAULT '' COMMENT 'trình duyệtLoại',
  `os_type` varchar(32) DEFAULT '' COMMENT 'hệ thống',
  `os_version` varchar(32) DEFAULT '' COMMENT 'hệ thốngphiên bản',
  `device_brand` varchar(32) DEFAULT '' COMMENT 'thiết bị',
  `device_model` varchar(64) DEFAULT '' COMMENT 'thiết bị',
  `ip` varchar(64) DEFAULT '' COMMENT 'địa chỉ IP',
  `ip_region` varchar(128) DEFAULT '' COMMENT 'khu vực IP',
  `is_current` tinyint(1) DEFAULT '0' COMMENT 'thiết bị',
  `last_login_at` int(11) DEFAULT '0' COMMENT 'Thời gian đăng nhập',
  `created_at` int(11) DEFAULT '0',
  `updated_at` int(11) DEFAULT '0',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_user_device` (`user_id`,`device_id`),
  KEY `idx_user_id` (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=51 DEFAULT CHARSET=utf8mb4 COMMENT='Người dùng登录设备Bảng';
/*!40101 SET character_set_client = @saved_cs_client */;

